mapper.select:
select exception_area, sodium, mercury, calcium, zinc, magnesium, detect_time
from mental
where exist_content = 1;

select exception_area, germ, fungus, animal, phage, detect_time
from organism
where exist_content = 1;

select exception_area, ray1, ray2, thorium, radium, uranium, detect_time
from radiation
where exist_content = 1;
